import { NavBar } from "./NavBar";
import { Footer } from "./Footer";
import { useState, useRef, useEffect } from "react";
import pattern from "../slike/pattern4.jpg";
import { useNavigate } from "react-router-dom";
export function Login(){

    const[email,setEmail]=useState("");
    const[lozinkaHash,setLozinka]=useState("");
      const imeRef = useRef(null);

      const navigate=useNavigate();

  useEffect(() => {
    imeRef.current.focus();
  }, []);

const handleSubmit = async (e) => {
  e.preventDefault();

 const encodedEmail = encodeURIComponent(email);
const encodedPassword = encodeURIComponent(lozinkaHash);

const endpoints = [
  { url: `http://localhost:8080/guests/login/${encodedEmail}/${encodedPassword}`, role: "gost" },
  { url: `http://localhost:8080/receptionists/login/${encodedEmail}/${encodedPassword}`, role: "recepcionar" }
];


  let loggedIn = false;

  for (let endpoint of endpoints) {
    try {
      const response = await fetch(endpoint.url, { method: "GET" });
      if (response.ok) {
        const data = await response.json();
       const user = data.data.value || data.data.receptionist;// <-- koristi "value" jer tvoj backend vraća ovako
        console.log(user);
        // postavljanje cookies
        document.cookie = `userEmail=${user.email}; path=/; max-age=86400`;
        document.cookie = `userId=${user.idGost || user.idRecepcionar}; path=/; max-age=86400`;
        document.cookie = `userRole=${endpoint.role}; path=/; max-age=86400`;

        // navigacija
        if (endpoint.role === "recepcionar") navigate("/recepcionar/dashboard");
        else navigate("/");

        loggedIn = true;
        break;
      }
    } catch (err) {
      console.error("Greška prilikom login-a:", err);
    }
  }

  if (!loggedIn) {
    alert("Neuspesan login! Pogledajte podatke.");
  }
};


return(
    <>
    <NavBar />
    <div style={{ backgroundImage: `url(${pattern})`,
    backgroundSize: "cover",   
    backgroundPosition: "center",
    minHeight: "100vh",         
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    flexDirection: "column"}}>
    <div className="forma" style={{with:"300px",height:"300px"}}>
        <form onSubmit={handleSubmit}>

        <span className="formaSpan">
            Unesite email
            <input type="email" onChange={(e)=>setEmail(e.target.value)} ref={imeRef} required />

        </span>
       <span className="formaSpan">
            Unesite lozinku
            <input type="password" onChange={(e)=>setLozinka(e.target.value)} required/>
        </span>

       <button type="submit" className="btnNav" style={{marginTop:"20px",border: "none",fontSize:"18px",width:"160px",height:"50px"}}>Napravi nalog</button>


</form>

    </div>
    </div>
    <Footer />
    </>
)


}
